const text =
  $json.output ||
  $json.text ||
  $json.message?.text ||
  $json.content ||
  "";

// Parse whole response as JSON
const data = JSON.parse(text);

return data;

const all = await $input.all();
const data = all[0].json;

// Expect fields from earlier steps present on the item:
// orderId, nextRevision, attendance, budget, menu_lines
const orderId = data.orderId;
const revision = Number(data.nextRevision);
const attendance = Number(data.attendance);
const budget = Number(data.budget);
const menu = Array.isArray(data.menu_lines) ? data.menu_lines : [];

const ts = new Date().toISOString();

return menu.map((m, idx) => {
  const lineId = m.line_id || String(idx + 1).padStart(3, "0");
  return {
    json: {
      OrderID: orderId,
      Revision: revision,
      IsCurrent: true,
      LineID: lineId,
      Category: m.category,
      Quantity: m.quantity,
      Item: m.item,
      Size: m.size || "",

    }
  };
});

const all = await $input.all();

// all items = each menu row just written
// we want a short grouped summary

const foods = [];
const drinks = [];

for (const item of all) {

  const r = item.json;

  if ((r.Category || "").toLowerCase() === "drink") {

    drinks.push(
      `${r.Quantity} ${r.Item}${r.Size ? " (" + r.Size + ")" : ""}`
    );

  } else {

    foods.push(
      `${r.Quantity} ${r.Item}`
    );
  }
}

// Build short summary text
let message = `✅ Catering order logged successfully.\n\n`;

if (foods.length) {

  message += `🍽 Food:\n`;

  message += foods.slice(0,5).map(f => `• ${f}`).join("\n");

  if (foods.length > 5) {

    message += `\n• +${foods.length - 5} more items`;
  }

  message += "\n\n";
}

if (drinks.length) {

  message += `🥤 Drinks:\n`;

  message += drinks.slice(0,5).map(d => `• ${d}`).join("\n");

  if (drinks.length > 5) {

    message += `\n• +${drinks.length - 5} more items`;
  }
}

return [
  {
    json: {
      telegramMessage: message
    }
  }
];

const all = await $input.all();

// If the read returned no items, emit one default item
if (!all || all.length === 0) {
  return [{
    json: {
      hasCurrentRows: false,
      currentRows: [],
      maxRevision: 0
    }
  }];
}

// Otherwise package the rows into one item
const rows = all.map(x => x.json);
const revs = rows.map(r => Number(r.Revision)).filter(n => Number.isFinite(n));
const maxRevision = revs.length ? Math.max(...revs) : 0;

return [{
  json: {
    hasCurrentRows: true,
    currentRows: rows,
    maxRevision
  }
}];

